import os
import re
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/reply')
def listFiles():
    '''
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username},
    list all the files and then return the list as a response.
    '''
    username = request.args.get('username', '')
    # Sanitize username: only allow alphanumeric, underscore, hyphen
    if not re.match(r'^[a-zA-Z0-9_-]+$', username):
        return Response("Invalid username", status=400)

    base_dir = '/home'
    user_dir = os.path.join(base_dir, username)

    # Ensure the resolved path is inside /home
    try:
        real_user_dir = os.path.realpath(user_dir)
        if not real_user_dir.startswith(os.path.realpath(base_dir) + os.sep) and real_user_dir != os.path.realpath(base_dir):
            return Response("Access denied", status=403)
    except Exception:
        return Response("Invalid path", status=400)

    if not os.path.isdir(real_user_dir):
        return Response("User directory not found", status=404)

    try:
        files = os.listdir(real_user_dir)
    except Exception:
        return Response("Permission denied", status=403)

    return Response('\n'.join(files), mimetype='text/plain')
